const inp = $input.first().json;
const body = inp.body || inp;

// Google AI Studio API key
const apiKey = 'BURAYA_GEMINI_API_KEY_GIRIN';
function fail(notes) {
  return {
    product_name: null, brand: null, model: null, category: null,
    weight_kg: null, length_cm: null, width_cm: null, height_cm: null,
    confidence: 0, notes, sources: [], error: true
  };
}

function parseJson(text) {
  if (!text) return null;
  const fence = String(text).match(/```(?:json)?\s*([\s\S]*?)```/i);
  let c = fence ? fence[1] : String(text);
  const s = c.indexOf('{'), e = c.lastIndexOf('}');
  if (s !== -1 && e !== -1) c = c.slice(s, e + 1);
  try { return JSON.parse(c); } catch { return null; }
}

function extractText(res) {
  return res?.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('\n').trim() || '';
}

function extractSources(res) {
  const chunks = res?.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const seen = new Set();
  return chunks.map(c => c.web).filter(Boolean).map(w => ({
    title: w.title || w.uri, uri: w.uri
  })).filter(s => { if (seen.has(s.uri)) return false; seen.add(s.uri); return true; });
}

async function callGemini(parts) {
  const models = ['gemini-2.5-flash', 'gemini-flash-latest', 'gemini-2.5-flash-lite'];
  let lastErr = null;
  for (const model of models) {
    const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;
    for (let i = 0; i < 2; i++) {
      try {
        return await this.helpers.httpRequest({
          method: 'POST', url,
          body: {
            contents: [{ role: 'user', parts }],
            tools: [{ google_search: {} }],
            generationConfig: { temperature: 0.2, maxOutputTokens: 2048 }
          },
          json: true
        });
      } catch (err) {
        lastErr = err;
        const msg = err.message || String(err);
        const retry = msg.includes('429') || msg.includes('503') || msg.includes('UNAVAILABLE') || msg.includes('RESOURCE_EXHAUSTED');
        if (retry && i < 1) { await new Promise(r => setTimeout(r, 2000)); continue; }
        if (retry) break;
        if (msg.includes('400') || msg.includes('401') || msg.includes('403') || msg.includes('API key')) {
          throw new Error('Gemini API key gecersiz. https://aistudio.google.com/app/apikey adresinden yeni key alin.');
        }
        throw err;
      }
    }
  }
  if (lastErr) {
    const msg = lastErr.message || String(lastErr);
    if (msg.includes('429') || msg.includes('quota')) throw new Error('Gemini API kotasi doldu. 1-2 dakika bekleyip tekrar deneyin.');
    if (msg.includes('503') || msg.includes('UNAVAILABLE')) throw new Error('Gemini su an yogun (503). 1-2 dakika bekleyip tekrar deneyin.');
    throw lastErr;
  }
}

try {
  if (!body.image) return [{ json: fail('Gorsel verisi bulunamadi.') }];

  const hint = body.hint || '';
  const mime = body.mimeType || 'image/jpeg';

  const prompt = `Sen lojistik urun analiz uzmanisin.

GOREV:
1) Fotograftaki urunu tani (ad, marka, model, kategori)
2) Google aramasi ile gercek agirlik (kg) ve boyutlari (cm) bul
3) Guven skoru ver (0-1)

${hint ? 'Kullanici ipucu: ' + hint : ''}

SADECE su JSON formatinda cevap ver (markdown YOK):
{
  "product_name": "string",
  "brand": "string veya null",
  "model": "string veya null",
  "category": "string",
  "weight_kg": number veya null,
  "length_cm": number veya null,
  "width_cm": number veya null,
  "height_cm": number veya null,
  "confidence": number,
  "notes": "string"
}`;

  const res = await callGemini.call(this, [
    { text: prompt },
    { inline_data: { mime_type: mime, data: body.image } }
  ]);

  const parsed = parseJson(extractText(res));
  if (!parsed) return [{ json: fail('AI cevabi JSON olarak cozumlenemedi.') }];

  const final = {
    product_name: parsed.product_name ?? null,
    brand: parsed.brand ?? null,
    model: parsed.model ?? null,
    category: parsed.category ?? null,
    weight_kg: parsed.weight_kg ?? null,
    length_cm: parsed.length_cm ?? null,
    width_cm: parsed.width_cm ?? null,
    height_cm: parsed.height_cm ?? null,
    confidence: parsed.confidence ?? 0.5,
    notes: parsed.notes ?? null,
    sources: extractSources(res),
    error: false
  };

  return [{ json: final }];
} catch (err) {
  return [{ json: fail('n8n hatasi: ' + (err.message || String(err))) }];
}
